"""
MKT Original Layer — Ezekiel chapters 18–20
Run: python3 scripts/zc-original-ezekiel-18-20-fill.py

Ch 18: Individual moral accountability — key terms: nephesh (soul/person, H5315,
  dispute_level 3), mut (die), shuv (turn/repent), boser (sour grapes), tsaddiq
  (righteous), avon (iniquity), pesha (transgression), tzedaqah (righteousness).
  The chapter is Ezekiel's moral-theology core: individual culpability without
  inherited guilt, repentance that genuinely wipes the slate, divine pleasure in life.
Ch 19: Qinah (lamentation) over the princes — lion/vine allegory. Key: qinah
  (H7015, the formal dirge meter); gur/ari (cub/lion imagery for Davidic kings);
  gefen (vine = Israel; Ps 80, Isa 5); matteh/shevet (branch/scepter = royal rule).
Ch 20: Pattern of covenant rebellion — major terms: bachar (choose), shaba (swear),
  yada (make known), huqqim/mishpatim (statutes/ordinances), shabbatot (sabbaths),
  ot (sign), qadash (sanctify), shem (name), yad hazaqah/zeroa netuyah (mighty
  hand/outstretched arm), yatsa (bring out — Exodus verb), bamah (high place).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZK_ORIG = {
  "18": {
    "1": "<p>Standard oracle formula: <em>vayhiy devar-YHWH elai lemor</em> — 'And the word of YHWH came to me saying.' The <strong>devar-YHWH</strong> (<em>davar</em>, H1697) formula occurs over 50 times in Ezekiel, more than any other book. It is both authorization and content — the word that comes is the word that creates reality.</p>",
    "2": "<p><strong>bosér</strong> (H1155, 'sour/unripe grapes'): rare word appearing only 4× in the OT (Isa 18:5; Jer 31:29-30; Ezek 18:2). The proverb — fathers eat unripe grapes and the children's teeth are set on edge — asserts inherited guilt and transferred punishment. YHWH challenges this proverb directly, not because corporate identity is false but because it was being used to deny personal accountability. The same proverb appears in Jer 31:29-30 in the new-covenant context.</p>",
    "3": "<p><strong>chay ani</strong> (<em>ḥay ʾānî</em>, 'as I live') — the divine oath formula. YHWH swears by his own life since there is no greater: the cessation of the proverb is guaranteed by divine self-commitment. This formula (unique to Ezekiel and Numbers) carries the force of the most solemn oath: YHWH's existence is pledged to the truth of what follows.</p>",
    "4": "<p><strong>kol-hanephashoth li hen</strong> ('all souls/persons belong to me — both'): <em>nephesh</em> (H5315, dispute_level 3) here means 'person' rather than the interior soul. The dispute in translation centers on whether <em>nephesh</em> is the animating breath-life, the whole person, or the appetite/desire. In this legal-accountability context, it is the person as a moral agent. <strong>hanephesh hachot'et hi tamut</strong> ('the soul/person who sins, that one shall die'): the stark individual liability principle. <em>tamut</em> from <em>mut</em> (H4191, die) — covenant death, not merely biological.</p>",
    "5": "<p><strong>tsaddiq</strong> (H6662, 'righteous/just one'): the righteous man is defined by what follows — a list of social, sexual, and cultic behaviors. <em>Tsaddiq</em> in Hebrew is primarily relational-covenantal: one who acts in accordance with the obligations of the covenant relationship (with YHWH and neighbor), not merely one with good inner character. The list that follows is a torah-like checklist of covenant fidelity.</p>",
    "6": "<p><strong>lo achal al-heharim</strong> ('he has not eaten at the mountain shrines'): cultic separation from idolatry. <strong>lo nissa einav el-gillulei beit yisrael</strong> ('he has not lifted his eyes to the idols of the house of Israel'): <em>gillulim</em> (H1544, Ezekiel's characteristic word for idols) is a derogatory term related to <em>galal</em> (dung/dung pellets) — a deliberately contemptuous designation. Ezekiel uses <em>gillulim</em> 38 times (more than all other OT books combined). <strong>lo timme</strong> ('he has not defiled') — <em>tame</em> (H2930, be unclean/defiled): ritual-moral contamination vocabulary from Leviticus applied to sexual ethics.</p>",
    "7": "<p><strong>chavlato</strong> ('his pledge/garment given as pledge'): <em>chabol</em> (H2254) means both 'to pledge' and 'to bind/destroy.' The returning of a pledge (especially a cloak taken as security for a debt, which Exod 22:25-26 and Deut 24:12-13 forbid keeping overnight) is the concretely poor person's protection. <strong>lachem nathen</strong> ('given food to the hungry') and <strong>erOM yechaseh</strong> ('covered the naked'): covenant welfare obligations derived from Deut 15 and Lev 19 — these are not works-of-supererogation but required covenant acts.</p>",
    "8": "<p><strong>beneshech lo yiten</strong> ('he has not lent at interest/usury'): <em>neshek</em> (H5392, 'bite/usury') — the word's root is 'to bite,' vividly depicting interest as the creditor's bite into the debtor. Lending at interest to fellow Israelites was prohibited (Exod 22:25; Lev 25:36-37; Deut 23:19-20). <strong>mishpat emet asah</strong> ('he has rendered honest/true judgment'): <em>emet</em> (H571, truth/faithfulness) — judgment that corresponds to reality rather than being distorted by bribery or favoritism (Lev 19:15).</p>",
    "9": "<p><strong>behuqqotai halach</strong> ('he has walked in my statutes'): <em>halak</em> (H1980, walk) as a covenantal metaphor for ongoing moral conduct — a Deuteronomic pattern (Deut 8:6; 10:12; 11:22). <strong>chayyoh yichyeh</strong> ('he shall surely live'): the infinitive absolute construction (<em>chayoh yichyeh</em>) emphasizes absolute certainty — this person will certainly, without qualification, live. <em>Chayah</em> (H2421, live) in this covenant context means covenantal life in YHWH's presence, not merely physical survival. Cf. Lev 18:5 ('the one who does them will live by them').</p>",
    "10": "<p><strong>ben paritz</strong> ('a son who is violent/a bandit'): <em>paritz</em> (H6530, violent one, robber) — the son's character is established by a single descriptor before the list of offenses. The contrast with the righteous father creates the generational counter-case: righteousness does not automatically transmit. <strong>shofech dam</strong> ('who sheds blood'): <em>shaphak dam</em> (H8210 + H1818) — the most serious covenant violation; blood is YHWH's domain (Gen 9:6; Deut 19:10).</p>",
    "11": "<p>The wicked son reverses each covenant obligation the righteous father kept. The structure is antiphonal: father 'does not eat at the mountain shrines' — son 'eats at the mountain shrines'; father 'does not defile his neighbor's wife' — son 'defiles.' The moral catalogue of ch 18 is among the most systematic presentations of covenant ethics in the prophets, approaching the form of a legal code (cf. the Decalogue and Lev 19).</p>",
    "12": "<p><strong>ani ve-evyon</strong> ('poor and needy'): the hendiadys pairing of <em>ani</em> (H6041, afflicted/humble/poor) and <em>evyon</em> (H34, needy/destitute) appears across the Psalms and prophets as the paradigmatic vulnerable person whom the covenant protects (Ps 72:12-13; Isa 41:17; Amos 8:4). Oppressing this pair defines the wicked man as the covenant's antithesis.</p>",
    "13": "<p><strong>beneshech natan vetarbit laqach</strong> ('he has lent at interest and taken profit'): both <em>neshek</em> (H5392, interest/usury, lit. 'bite') and <em>tarbit</em> (H8636, increase/profit on a loan) appear together here — the legal doublet covers all forms of financial exploitation of the poor. The verdict: <strong>mot yumat — damo bo yihyeh</strong> ('he shall surely die — his blood is upon himself'). The death is judicial: YHWH holds the debt of blood for covenant violations.</p>",
    "14": "<p>The third-generation case: a son who observes his father's wickedness, <strong>vayar</strong> ('and he sees/considers') — the seeing is morally active, not passive observation. <strong>velo yaaseh kahen</strong> ('and does not do likewise'): the son's non-conformation to the father's pattern is itself a moral achievement, enabled by the seeing and considering. This counters fatalism about moral inheritance.</p>",
    "15": "<p>The third-generation righteous son's list mirrors the first-generation righteous father's list (vv.6-9) nearly verbatim — demonstrating that righteousness is a pattern that can recur across generations even when the intervening generation was wicked. Moral character is neither automatically inherited nor automatically blocked by parental failure.</p>",
    "16": "<p><strong>lo hitziq</strong> ('he has not oppressed'): <em>hitziq</em> from <em>yatzaq</em> (H3238, oppress/wrong) or more likely <em>atzaq</em> — the not-taking of the pledge, not-robbing, giving food and clothing: the second-generation wicked son's exact opposites, the third generation now mirrors the first in covenant fidelity.</p>",
    "17": "<p><strong>lo yamut beavon aviv</strong> ('he shall not die for the iniquity of his father'): <em>avon</em> (H5771, iniquity/guilt/punishment for iniquity) — the word covers both the act and its consequence. The son is not absolved of his father's <em>avon</em> on a technicality; rather, YHWH's justice is structured so that individual moral agency is the determining factor, not genealogical inheritance.</p>",
    "18": "<p><strong>asher oshaq oshek</strong> ('because he practiced cruel oppression'): <em>ashaq</em> (H6231, oppress) doubled for emphasis — persistent, habitual oppression. <strong>gozal gazal</strong> ('robbed by violence') — <em>gazal</em> (H1497, rob/seize) similarly doubled. The father's death is entirely his own doing: <em>beavono yamut</em> ('in his iniquity he will die'). The covenant's moral economy is precise.</p>",
    "19": "<p>The people's objection (<em>lama</em>, 'why?') reflects cognitive dissonance with Deuteronomic theology: the tradition of Exod 20:5 (visiting iniquity on third and fourth generations) was understood by the exiles as explaining their suffering — but they were using it to escape personal accountability. YHWH's answer reframes the tradition: generational consequences operate at the level of community covenant identity, not individual forensic standing.</p>",
    "20": "<p><strong>hanephesh hachot'et hi tamut</strong> ('the soul/person that sins — that one shall die'): the principle stated again for emphasis. <strong>tzidqat hatzaddiq alav tihyeh verishah harasha alav tihyeh</strong> ('the righteousness of the righteous belongs to him, and the wickedness of the wicked falls on him'): <em>tzedaqah</em> (H6666, righteousness/right-doing/right-standing) is not transferable; <em>risha</em> (H7564, wickedness/wrong-doing) is not inflicted on others. This is the bedrock principle of Ezekiel's moral theology.</p>",
    "21": "<p><strong>vehu yashuv mikol chatotav</strong> ('and he turns from all his sins'): <em>shuv</em> (H7725, turn/return/repent) — the most important repentance verb in the OT. Appears 1,101× in the OT; Ezekiel uses it intensively. The turn is from (<em>min</em>) sins toward (<em>el</em>) YHWH's statutes. <strong>chayoh yichyeh lo yamut</strong> ('he shall surely live, he shall not die'): the double statement (positive then negative) is the strongest possible legal guarantee of life. The turning itself opens the forensic file of life.</p>",
    "22": "<p><strong>kol-peshaav</strong> ('all his transgressions'): <em>pesha</em> (H6588, rebellion/transgression) — the most serious Hebrew sin term, denoting willful breach of a covenant relationship (as between vassal and suzerain). <strong>lo yizakeru lo</strong> ('will not be remembered against him'): <em>zakar</em> (H2142, remember) in a covenant context: YHWH's 'not remembering' is a covenantal act of amnesty, not mere forgetfulness. The forgiven <em>pesha</em> is sealed shut in the divine ledger — a promise with legal force.</p>",
    "23": "<p><strong>hachapots achapots beMOT harasha</strong> ('do I really delight in the death of the wicked?'): the rhetorical question is divine self-revelation. <em>chaphets</em> (H2654, delight/desire/take pleasure in) — YHWH takes no pleasure in covenant death sentences; justice is not his goal, life is. <strong>im-lo veshuvo miderachav vechai</strong> ('rather that he should turn from his ways and live'): the divine will expressed in the <em>im-lo</em> ('is it not rather') construction. This verse is the theological heart of the chapter.</p>",
    "24": "<p><strong>uveshuv hatzaddiq mitzidqato</strong> ('when the righteous person turns from their righteousness'): the counter-case: the righteous person who turns away forfeits their accumulated righteousness. <strong>kol-tzidqotav asher asah lo yizakeru</strong> ('none of their righteous deeds will be remembered'): the negative counterpart of v.22 — just as the forgiven sinner's record is cleared, the apostate's righteous record is wiped. The ledger is always current, not cumulative-permanent in either direction.</p>",
    "25": "<p><strong>lo yitaken derech YHWH</strong> ('the way of the LORD is not fair/right'): the people's accusation against YHWH's justice. <em>takan</em> (H8505, to weigh out/measure/make right/be equitable) — used of accurate weights (Prov 16:2; 21:2; 24:12). The accusation is that YHWH's moral accounting is not properly balanced. YHWH reverses the charge: it is <em>their</em> ways that are not <em>takan</em>.</p>",
    "26": "<p>The principle restated: <em>shuv</em> from righteousness toward iniquity → death; the iniquity he commited (<em>beavono asher asah</em>) is the cause. YHWH's statement is not harsh but logical: if one chooses iniquity over the covenant relationship, one chooses the consequence.</p>",
    "27": "<p><strong>uveshuv rasha merishtato</strong> ('when the wicked person turns from their wickedness'): <em>risha</em> (H7564, wickedness) → <em>shuv</em> (turn) → doing what is just and right (<em>mishpat utzedaqah</em>). <strong>hu yechayeh et-nafsho</strong> ('he will save his own life/soul'): literally 'he will keep his <em>nephesh</em> alive.' The turning person is the agent of their own life-keeping — YHWH's justice rewards the genuine turning.</p>",
    "28": "<p><strong>vayyar vayashav</strong> ('because he has considered and turned'): the sequence of seeing-and-turning is the moral process Ezekiel envisions. <em>ra'ah</em> (H7200, see) here means moral reflection — taking stock of one's trajectory. The turning follows from genuine moral sight, which is why the wicked son of v.14 who 'sees and does not do likewise' is the positive counterpart.</p>",
    "29": "<p>The accusation repeated a second time: <em>lo yitaken derech YHWH</em>. YHWH's answer is consistent: he will judge each one by their own ways (<em>ish kidrachav</em>). The repetition (also in v.25) signals the depth of the dispute — this is not academic theology but the exiles' actual complaint against the justice of their situation.</p>",
    "30": "<p><strong>shuvu vehashivu mikol-pisheichem</strong> ('repent and turn from all your transgressions'): the double imperative — <em>shuv</em> twice (repent! and turn!) — is the pastoral application of the theology. <strong>velo-yihyeh lachem lemichshol avon</strong> ('so that iniquity will not be your downfall'): <em>michshol</em> (H4383, stumbling-block/occasion of falling) — the accumulated iniquity that causes one to stumble. Repentance preempts the stumbling.</p>",
    "31": "<p><strong>hashlichu mealeichem et-kol-pisheeichem</strong> ('cast away from you all your transgressions'): active imperative — the human agent must throw off the weight of accumulated rebellion. <strong>vaasu lachem lev chadash veruach chadasha</strong> ('make for yourselves a new heart and a new spirit'): the command that anticipates its own impossibility, resolved in 36:26-27 where YHWH promises to give what he here commands. The gap between command and ability is the pneumatological space that the new covenant fills.</p>",
    "32": "<p><strong>ki lo achapots beMOT haMet</strong> ('for I have no pleasure in the death of anyone who dies'): <em>haMet</em> — 'the one who dies,' emphasizing that this is about actual deaths, not abstract principles. <strong>shuvu vechyu</strong> ('turn and live!'): the two-word summary of the entire chapter. Ezekiel's prophetic imperative at its briefest and most urgent. The entire chapter is a theological framework for the possibility and urgency of this simple command.</p>"
  },
  "19": {
    "1": "<p><strong>veath sa qinah</strong> ('raise up a lamentation/dirge'): <em>qinah</em> (H7015, formal dirge/elegy) — the distinctive Hebrew meter of 3+2 stresses associated with mourning (first systematically identified in Lamentations). Ezekiel's use of qinah-form for <em>living</em> kings is a prophetic death-announcement in literary form: to be the subject of a qinah is to be declared already dead in the prophetic vision. The form creates the reality it describes.</p>",
    "2": "<p><strong>labiya</strong> (H3833, 'lioness'): the feminine form of lion, used for the mother who is also a figure of royal power. <strong>ben-ariot rabisat</strong> ('she lay down among lions'): <em>ari</em> (H738, lion) is the standard word for the mature male lion; <em>labia</em> is the mother. The royal house of Israel as a pride of lions draws on the Judah-lion blessing (Gen 49:9). <strong>gur</strong> (H1482, 'cub/whelp'): the young lion whose potential for royalty has not yet been tested.</p>",
    "3": "<p><strong>vayyilmad litrop terep</strong> ('he learned to catch prey/to tear prey'): the education of the young king in the practice of power. <em>tarap</em> (H2963, to tear/rend) — predatory, violent acquisition of power. <strong>adam achal</strong> ('he devoured men'): the lioness/king who devours his own subjects — the parable indicts the predatory nature of Judah's late monarchy, contrasting with the Good Shepherd of ch 34.</p>",
    "4": "<p><strong>vayishmehu goyim bashuachot nilkad</strong> ('the nations heard about him; he was caught in their pit'): <em>shuachat</em> (H7825, pit/trap/snare) — the pit that catches the lion is the Babylonian military trap. This refers to Jehoahaz (609 BCE), the first lion-cub, who was taken in chains to Egypt (2 Kgs 23:33-34). The <em>nations</em> that set the trap are Egypt in this first case, contrasting with Babylon in the second.</p>",
    "5": "<p><strong>vatere ki nivchelah</strong> ('when she saw that her hope was deferred'): <em>yachal</em> (H3176, wait/hope) — the mother-lioness waiting for the return of the first cub, finally abandoning hope. <strong>tiqvatah aveda</strong> ('her hope was gone/lost'): <em>tiqvah</em> (H8615, hope/cord) — the same word as Rahab's scarlet cord (Josh 2:18): a thread of hope that can be cut. The mother's hope is extinguished by Jehoahaz's fate.</p>",
    "6": "<p>The second lion-cub (Jehoiachin or Zedekiah) learns the same predatory pattern. The repetition of the learning-sequence emphasizes the structural failure: not a one-off bad king but an institutional pattern of royal predation. <strong>vayyilmad litrop terep</strong> — 'he learned to catch prey': the same phrase as v.3, the educational cycle of violence repeating.</p>",
    "7": "<p><strong>vayeda almanotav</strong> ('he ravaged their strongholds/widow-cities'): <em>almanot</em> can mean 'widows' or 'palaces/citadels' — the text may be deliberately ambiguous. The second interpretation (palaces/strongholds) fits the military context; the first (widows) accuses the king of preying on the most vulnerable. The ambiguity may be intentional: the king who destroys cities leaves behind widows.</p>",
    "8": "<p><strong>vayitnu alav goyim miseviv mimdinot</strong> ('the nations gathered against him from the surrounding provinces'): the international coalition that closed in on the second cub. The spreading net (<em>resheth</em>, H7568) imagery: the lion is now prey, caught in what had previously been his hunting ground. The reversal of predator-to-prey is the poetic justice of the lamentation.</p>",
    "9": "<p><strong>vayyitenuhu basugar bachachim</strong> ('they put him in a cage/enclosure in chains'): <em>sugar</em> (H5474, cage/enclosure for dangerous animals) — a royal lion caged is the ultimate humiliation. <strong>velo-nishma qolo od al-harei yisrael</strong> ('so that his voice would no longer be heard on the mountains of Israel'): the silencing of the royal voice is the defining loss. A king's authority is expressed through his voice commanding the realm; the cage ends the commands. Contrast: the voice of YHWH that speaks through the prophets cannot be caged.</p>",
    "10": "<p><strong>imecha kagefen bedamecha</strong> ('your mother was like a vine in your vineyard/among the waters'): a second allegory begins: the lioness-mother is now reimagined as a vine. <em>gefen</em> (H1612, vine) — Israel as YHWH's vine is a fundamental OT metaphor (Ps 80:8-16; Isa 5:1-7; Jer 2:21; John 15:1). <strong>meme-mayim</strong> ('beside/among the waters'): the well-watered vine as image of prosperity — Israel's earlier flourishing under the Davidic monarchy.</p>",
    "11": "<p><strong>vayihyu-lo mattot azim</strong> ('she had strong/mighty branches/rods'): <em>matteh</em> (H4294, rod/branch/staff/tribe) — the strong branches that serve as rulers' scepters. The word simultaneously means the ruling rod (scepter of authority) and the branch of the vine (natural growth). This double meaning is the allegory's point: the branches that grow naturally also become the instruments of royal rule. <strong>shevet moshel</strong> ('scepter/rod of a ruler'): <em>shevet</em> (H7626) is both tribal affiliation and governing rod — Gen 49:10's 'the scepter shall not depart from Judah.'</p>",
    "12": "<p><strong:>vatitash bachema</strong> ('she was torn up in anger/fury'): <em>amar</em> (H2534, fury/heat of anger) — divine wrath as the active force behind the Babylonian destruction. <strong>veruach haqqadim hobish piryo</strong> ('the east wind dried up her fruit'): <em>ruach qadim</em> (east wind) is the consistent metaphor for Babylon in Ezekiel (17:10; 19:12; 27:26) — the wind from the Mesopotamian desert/steppe that scorches and kills vegetation. The Babylonian conquest is the east wind that dries up the Davidic vine.</p>",
    "13": "<p><strong>veata shetulatbemdbar bearetz tziyah vetzama</strong> ('now she is planted in the wilderness — in a dry and thirsty land'): the transplanted vine in the wilderness is the exile itself. <em>tziyah</em> (H6723, dry ground/drought) and <em>tzama</em> (H6772, thirst) create a merism of waterless desolation, the opposite of the well-watered condition of v.10. The covenant land's fruitfulness is lost; the exile is drought.</p>",
    "14": "<p><strong>vatetzeh esh mimmatteh badeha</strong> ('fire has spread from one of her branches'): the fire within the vine — internal destruction. This may refer to Zedekiah's rebellion against Babylon, which brought the final conflagration. <strong>ein-ba matteh-oz shevet lemoshel</strong> ('she has no strong branch left — no scepter/rod to rule with'): the Davidic monarchy's effective end. The lamentation is sealed with <strong>hi qinah vatehyi liqinah</strong> ('this is a lamentation and has been used as a lamentation'): the meta-statement about the genre — Ezekiel is aware he is composing liturgical mourning-poetry, and declares it will be used as such. The qinah outlives the events it mourns.</p>"
  },
  "20": {
    "1": "<p>Precise dating: seventh year, fifth month, tenth day — about 591 BCE. <strong>anashim mizziqnei yisrael</strong> ('some of the elders of Israel'): <em>zeqenim</em> (H2205, elders) — the leadership delegation. <strong>lidrosh et-YHWH</strong> ('to inquire of/seek YHWH'): <em>darash</em> (H1875, inquire/seek/resort to) — the technical verb for prophetic consultation. YHWH refuses to be consulted by those who will not repent.</p>",
    "2": "<p>Standard messenger formula. The chapter that follows is Ezekiel's most extensive historical review — a covenant lawsuit (riv) tracing four generations of rebellion from Egypt to the present, in a structure that shows each generation receiving grace and abusing it, followed by divine restraint for the sake of the divine Name.</p>",
    "3": "<p><strong>im-yiddaresh ani lachem</strong> ('I will not let myself be consulted by you'): the divine refusal to be 'inquired of' (<em>darash</em>) by those who continue in idolatry. This is not divine accessibility — it is divine integrity. YHWH does not provide oracular guidance while the inquirers maintain contradictory loyalties. The Niphal of <em>darash</em> here ('I will not be sought/consulted') is emphatic self-distancing.</p>",
    "4": "<p><strong>hashophet otam</strong> ('will you judge them?'): YHWH asks Ezekiel to pronounce judgment by making known their fathers' abominations. The forensic vocabulary (shaphat, H8199, judge) positions the entire historical review as a legal indictment. <strong>hoda otam et-toavot avotam</strong> ('make known to them the abominations of their fathers'): <em>toavah</em> (H8441, abomination/detestable thing) — Ezekiel's other characteristic word for religious betrayal, alongside <em>gillulim</em>.</p>",
    "5": "<p><strong>vaevachar beyisrael</strong> ('I chose Israel'): <em>bachar</em> (H977, choose/select) — the divine election vocabulary. <strong>vaessa yadi</strong> ('I raised my hand/swore'): the oath gesture — raising the hand is the physical accompaniment of the most solemn oath. YHWH's choosing of Israel is grounded in sovereign grace, not Israel's merit (Deut 7:6-8). <strong>lezara beit-yaaqov</strong> ('to the seed/offspring of the house of Jacob'): the election reaches back to the patriarchal promise.</p>",
    "6": "<p><strong>eretz zavat chalab udvash</strong> ('a land flowing with milk and honey'): the Exodus-formula for the Promised Land (Exod 3:8,17; Lev 20:24; Num 14:8; Deut 6:3 etc.) — occurring 20× in the Pentateuch. In Ezekiel's retrospective it becomes evidence of YHWH's gracious intent: the gift was always the goal. <strong>tzvi hi lechol haaratzot</strong> ('the most glorious/the glory of all lands'): <em>tzvi</em> (H6643, glory/beauty/gazelle) — the land as the beautiful prize, the destination of YHWH's desire for his people.</p>",
    "7": "<p><strong>ish et-shiqutzei einav hashlichu</strong> ('each of you must cast away the detestable things of his eyes'): <em>shiqutzim</em> (H8251, detestable things/abominations) — idols described by what they do to the senses: they are things the eyes desire (<em>einav</em>). <strong>vebegillulei mitzraim al-titammeu</strong> ('do not defile yourselves with Egypt's idols'): the idolatry Israel must leave behind in Egypt is already in their hearts. The Exodus is as much an inner detachment from Egypt as a geographic departure.</p>",
    "8": "<p><strong>vayamru lo nishma elecha</strong> ('but they rebelled against me and would not listen'): <em>marah</em> (H4784, rebel/be contentious) — the first rebellion, in Egypt itself, before the Exodus. The failure to cast away Egyptian idols (v.7) was not ignorance but refusal. <strong>eshpoch chamati</strong> ('I said I would pour out my fury'): <em>shaphak</em> (H8210, pour out) + <em>chemah</em> (H2534, fury/heat) — the covenant anger that was consistently restrained throughout the history.</p>",
    "9": "<p><strong>vaase lema'an shemi</strong> ('but I acted for the sake of my name'): the theological pivot that recurs four times in this chapter (vv.9,14,22,44). <em>shem</em> (H8034, name) — YHWH's name is his reputation, his identity-in-relationship, his covenant self-disclosure. To act 'for the sake of my name' is to maintain covenant integrity even when the covenant partner has forfeited it. <strong>lehallel</strong> ('to be profaned'): <em>chalal</em> (H2490, profane/defile/pierce) — the Niphal: YHWH's name would be profaned if he destroyed Israel before the watching nations, for they would conclude his power was limited.</p>",
    "10": "<p><strong>vaotzi otam me-eretz mitzraim</strong> ('so I brought them out of Egypt'): <em>yatsa</em> (H3318, go out/bring out) in the Hiphil — the Exodus verb. The word appears throughout the chapter (vv.6,9,10,14,22,34,38,41,42) as the theological backbone: YHWH's primary redemptive act is the bringing-out, and this chapter recasts it as the beginning of a pattern that will be repeated in the new exodus from Babylon.</p>",
    "11": "<p><strong>vaeten lahem et-chuqqotai</strong> ('I gave them my statutes'): <em>choq</em> (H2706, statute/engraving) — the word for law as something engraved or incised, fixed and permanent. Alongside <em>mishpatim</em> (H4941, ordinances/judgments — from <em>shaphat</em>, to judge). <strong>asher yaaseh otam haadam vachai bahem</strong> ('which if a person does them, he will live by them'): the Lev 18:5 citation — the principle that the law contains life within it; doing the law is the path to life. Paul cites this in Gal 3:12 and Rom 10:5 to contrast with the righteousness of faith.</p>",
    "12": "<p><strong>vegam et-shabbetotai natati lahem</strong> ('I also gave them my sabbaths'): <em>shabbat</em> (H7676, sabbath/rest) — the gift vocabulary is striking: the sabbath is not a burden imposed but a grace bestowed. <strong>lihyot leot beni uveinam</strong> ('as a sign between me and them'): <em>ot</em> (H226, sign/token/signal/wonder) — the sabbath as the distinguishing mark of the covenant, the visible indicator of the YHWH-Israel relationship in time (Exod 31:13-17). <strong>ledet ki ani YHWH meqaddisham</strong> ('so they would know that I am YHWH who sanctifies them'): <em>qadash</em> (H6942, be holy/sanctify/set apart) — YHWH as the sanctifier; the sabbath is the temporal enactment of Israel's holiness.</p>",
    "13": "<p><strong>vayimredu vi beit yisrael</strong> ('but the house of Israel rebelled against me'): the rebellion in the wilderness — the Sinai-to-Kadesh generation. <strong>veet-shabbetotai chilelu mead</strong> ('they profaned my sabbaths greatly'): <em>chalal</em> (H2490, profane) + <em>meod</em> (greatly/exceedingly) — the sabbath violation as particularly significant because the sabbath is the sign of the covenant; profaning it attacks the visible token of the relationship itself.</p>",
    "14": "<p><strong>vaase lema'an shemi</strong> ('but I acted for the sake of my name'): second occurrence of the name-protection motif. The restraint of the justified divine wrath 'for the sake of the name' is the OT foundation for Paul's theology of divine forbearance in Rom 3:25-26 — God passing over former sins during the period before the cross.</p>",
    "15": "<p><strong>vegam ani nasati yadi lahem bamidbar</strong> ('but I also swore in the wilderness'): the second oath, negative — not to bring them into the land. The land that YHWH described positively in v.6 (<em>tzvi... zavat chalab udvash</em>) is now withheld from the rebellious generation. The greatness of the gift makes the withholding more pointed.</p>",
    "16": "<p><strong>ki bemishpatai maasu</strong> ('because they despised my ordinances'): <em>maas</em> (H3988, despise/reject/refuse) — the active rejection of the covenant's defining content. <strong>velibam holech acharei gilluleihem</strong> ('their hearts were set after/followed their idols'): <em>lev</em> (H3820, heart) — the directing of the inner person after <em>gillulim</em> (H1544, idols/dung-pellets). The heart going after idols is the covenant betrayal that explains every external violation.</p>",
    "17": "<p><strong>vatachos eini alehem mishachet</strong> ('nevertheless my eye had pity on them, not destroying them'): <em>chus</em> (H2347, spare/have compassion on) — the unexpected mercy that interrupts the pattern of rebellion-judgment. YHWH's pity is not earned; it appears as a grace-moment within the judgment narrative. This recurs throughout the chapter as the divine counter-pattern to human unfaithfulness.</p>",
    "18": "<p><strong>vaomar el-beneihem bamidbar</strong> ('and I said to their children in the wilderness'): the second generation receives direct instruction after the first generation is barred from the land. The instruction begins with negative commands: <strong>behuqqot avoteichem al-telechu</strong> ('do not follow your fathers' statutes') — the children are warned against inheriting their parents' patterns, not against the covenant itself.</p>",
    "19": "<p><strong>ani YHWH eloheichem</strong> ('I am YHWH your God'): the Decalogue's opening formula (Exod 20:2; Deut 5:6) — the covenant identity declaration that grounds all the following commands. <strong>bechukotai telechu</strong> ('walk in my statutes'): <em>halak</em> (H1980, walk) as the metaphor for conduct — life as movement in a direction, with YHWH's statutes as the path.</p>",
    "20": "<p><strong>et-shabbetotai qaddoshu</strong> ('keep my sabbaths holy'): <em>qadash</em> in Piel (H6942, to sanctify/treat as holy) — the human responsibility to treat the sabbath as the holy thing YHWH has made it. <strong>vehayo leot beni uveinechem</strong> ('they will be a sign between me and you'): the sabbath as the covenant-identity marker appears in this chapter's context as the single most important distinguishing practice — its observance or neglect becomes the synecdoche for covenant fidelity or betrayal.</p>",
    "21": "<p>The second generation rebels as the first did — the structural repetition shows the depth of the problem. Neither the punishment of the first generation nor the explicit instruction (vv.18-20) breaks the cycle. <strong>veshabbetotai chilelu</strong> ('they profaned my sabbaths'): the sabbath-profanation recurs. The pattern cannot be broken by law, instruction, or punishment — which sets up the new covenant promise of 36:26-27 where YHWH says he will act internally rather than externally.</p>",
    "22": "<p><strong>vaasef et-yadi</strong> ('but I withdrew my hand'): the restraint of divine judgment — 'pulling back' the hand raised for punishment. Third occurrence of the name-protection motif. YHWH's consistency in holding back judgment 'for the sake of my name' across three generations reveals the patient divine pedagogy: the repeated offer of repentance, the repeated restraint of deserved judgment.</p>",
    "23": "<p><strong>gam ani nasati et-yadi lahem bamidbar lehafitz otam bagoyim</strong> ('but I also swore to scatter them among the nations'): the counter-oath — the promise of judgment-through-scattering that Lev 26:33 and Deut 4:27; 28:64 established. The dispersion is not an accident of history but a covenant consequence. The exile is therefore not YHWH's abandonment of his people but the execution of a covenantal clause that Israel itself agreed to (Deut 27-28).</p>",
    "24": "<p><strong>veyaen bemishpatai lo asu</strong> ('because they had not carried out my ordinances'): the three-part indictment — rejected <em>mishpatim</em>, despised <em>huqqim</em>, profaned <em>shabbatot</em>, and hearts after fathers' idols. The sabbath-profanation appears again as the lead indicator: to violate the sign is to dissolve the relationship it signifies.</p>",
    "25": "<p><strong>vegam ani natati lahem huqqim lo tovim</strong> ('I also gave them statutes that were not good'): this troubling verse refers to YHWH giving over Israel to the consequences of their own rebellious choices — 'statutes not good' meaning the idolatrous practices they already followed, which YHWH 'gave' them by withdrawing his restraining hand. The 'statutes by which one cannot live' are the self-destructive practices of the nations (cf. Rom 1:24,26,28: God 'gave them over' to their desires).</p>",
    "26": "<p><strong>vatimme otam bematnotam</strong> ('I made them unclean through their own offerings'): the defilement by one's own offerings — particularly child sacrifice (<em>behaavir kol-peter rechem</em>, 'in causing every firstborn to pass through the fire'). This is the bitter irony: what they intended as worship YHWH counted as self-contamination. <strong>lema'an ashem</strong> ('so that they might be desolate/appalled'): <em>shamem</em> (H8074, be desolate/appalled) — the horror of seeing one's own actions lead to desolation.</p>",
    "27": "<p><strong>uven bigedu vi avoteichem</strong> ('your fathers committed treachery against me'): <em>baged</em> (H898, act treacherously/faithlessly) — the covenant betrayal vocabulary from the marriage metaphors of Hosea and Jeremiah. <strong>maalo maalu vi</strong> ('they committed unfaithfulness against me'): <em>maal</em> (H4603, act treacherously/commit trespass) — the doubling intensifies: persistent, habitual covenant unfaithfulness.</p>",
    "28": "<p><strong>vaaviEM el-haaretz</strong> ('when I brought them into the land'): the transition from wilderness to settlement — the land-gift that should have ended the cycle. Instead: <em>kol-givah ramah</em> ('every high hill') and <em>kol-etz avot</em> ('every leafy tree') become sites of sacrifice. The land that was to be the locus of pure YHWH-worship becomes instead the expansion of Canaanite high-place practice.</p>",
    "29": "<p><strong>mah-habamah asher atem habaim sham</strong> ('what is this high place to which you go?'): YHWH's question about the bamah — the word-play on <em>bama</em> (H1116, high place) may be connected to <em>ba</em> (H935, come/go) to suggest 'the place-you-go-to.' The name <em>Bamah</em> sticks ('its name has been called Bamah to this day') as an indictment: the illicit worship site has become a named landmark of disobedience.</p>",
    "30": "<p><strong>hagedrekei avoteichem atem nitmaim</strong> ('are you making yourselves unclean in the same way as your fathers?'): the rhetorical question with a known answer. <strong>acharei shiqutzeihem atem zonim</strong> ('do you go whoring after their detestable things?'): <em>zanah</em> (H2181, whore/commit fornication/be unfaithful) — the marriage-covenant vocabulary: idolatry as adultery. This connects to Ezekiel's extended use of sexual-unfaithfulness imagery for religious betrayal (chs 16, 23).</p>",
    "31": "<p><strong>uvehaniash mattanotechem</strong> ('when you present your gifts'): the child-sacrifice language recurs (<em>behaavir benaichem baesh</em>). <strong>im-yiddaresh ani lachem</strong> ('I will not be consulted by you'): the refusal to respond to hypocritical inquiry, as in v.3. The chapter's frame: the elders came to inquire; YHWH refuses; he instead reviews their history to explain why the consultation is invalid.</p>",
    "32": "<p><strong>vehaaolah al-ruchechem hayoh lo tihyeh</strong> ('what you are thinking will not happen'): <em>ruach</em> (H7307, spirit/breath/wind) here used for 'thought/mind.' The people's desire to be like the nations (<em>kegoyim</em>) and worship wood and stone is a direct repudiation of Israel's covenant calling (Deut 4:5-8; 14:2). YHWH refuses this self-assimilation: the calling cannot be discarded.</p>",
    "33": "<p><strong>chay ani</strong> — the divine oath. <strong>beyad chazaqah uvizroa netuyah</strong> ('with a mighty hand and outstretched arm'): the Exodus formula (Deut 4:34; 5:15; 7:19 etc.) — the most recognizable shorthand for YHWH's redemptive power. The same mighty hand and outstretched arm that brought Israel out of Egypt will govern their return from exile. <strong>uvecheimah shefuchah</strong> ('and with outpoured fury'): the return will not be without judgment; the new exodus passes through a wilderness of accountability before reaching restoration.</p>",
    "34": "<p><strong>vehozeti etchem min-haammim</strong> ('I will bring you out from the peoples'): <em>yatsa</em> (H3318) again — the bringing-out verb of the Exodus applied to the return from exile. The new exodus pattern is explicit: the same mighty hand, the same bringing-out, the same journey toward the covenant relationship — but after a severe discipline.</p>",
    "35": "<p><strong>vahaveti etchem el-midbar haamim</strong> ('I will bring you into the wilderness of the peoples'): the new exodus will include a new wilderness — a place of divine confrontation before the land is entered. <strong>venispot etchem sham panim el-panim</strong> ('and there I will contend with you face to face'): <em>panim el-panim</em> — the direct personal confrontation (cf. Gen 32:30, Jacob wrestling with God face to face). The wilderness of peoples is a space for the covenant lawsuit to be prosecuted personally.</p>",
    "36": "<p><strong>kaasher nispot et-avoteichem bemidbar eretz mitzraim</strong> ('as I contended with your fathers in the wilderness of Egypt'): the wilderness of the nations will replicate the Sinai wilderness experience — a second giving of the covenant. The new exodus recapitulates the first; the God who acted then will act again in the same pattern.</p>",
    "37": "<p><strong>vehaaveti etchem tachat hashevet</strong> ('I will cause you to pass under the shepherd's rod'): <em>shevet</em> (H7626, rod/staff/tribe/scepter) — the shepherd's counting-rod. In ancient practice, sheep passed under the rod one by one for counting and inspection (Lev 27:32). <strong>uveheveti bemasoret habrit</strong> ('and I will bring you into the bond/chain of the covenant'): <em>massoret</em> (H4562, chain/bond) — the covenant as a binding obligation. The image is both protective (flock under the shepherd's care) and obligating (the covenant that binds both parties).</p>",
    "38": "<p><strong>uvaroti mikem hamordim vehamopeshim bi</strong> ('I will purge out from among you the rebels and those who sin against me'): <em>barar</em> (H1305, purge/purify/select) — the purging of the dross from the refined metal; the same term appears in Mal 3:3 (the refiner's fire). The return is selective: the rebels will be removed before the restored community enters the land. The exodus-through-the-wilderness produces a purified remnant.</p>",
    "39": "<p>The bitter irony of YHWH's concession: if you will not listen, at least stop defiling his name with your <em>gillulim</em>. The minimum demand — if you cannot stop idolatry, at least do not mix it with YHWH-worship. This is not approval of idolatry but the final statement before the positive turn of vv.40-44: half-hearted worship is worse than straightforward defection because it pollutes the name.</p>",
    "40": "<p><strong>bebhar qodshi</strong> ('on my holy mountain'): the eschatological gathering point. <strong>sham yaaveduni kol-beit yisrael kuloh</strong> ('there all the house of Israel — all of it — will serve me'): the restored worship is complete-Israel worship: no division, no partial remnant — <em>kuloh</em> ('all of it') — the healing of the division between north and south, the ingathering of all the dispersed. <strong>sham eratzehem</strong> ('there I will accept them'): <em>ratzah</em> (H7521, be pleased with/accept/satisfy a debt) — divine acceptance of the restored offering.</p>",
    "41": "<p><strong>berei'ach nichoach ertzechem</strong> ('I will accept you as a pleasing aroma'): <em>rei'ach nichoach</em> (H7381 + H5207) — the 'pleasing aroma' of acceptable sacrifice (Gen 8:21; Exod 29:18,25,41; Lev 1:9,13,17 etc.) — the technical term for what makes an offering acceptable to YHWH. The restored people are themselves the pleasing sacrifice. <strong>venikdashti bachem leeinei hagoyim</strong> ('I will show my holiness through you before the nations'): the priestly-national vocation of Israel (Exod 19:5-6) is fulfilled in the restoration: YHWH is sanctified before the nations through the visible restoration of his people.</p>",
    "42": "<p><strong>vidate'u ki ani YHWH</strong> ('you will know that I am YHWH'): the recognition formula that runs through Ezekiel — in exile the Israelites will know YHWH because of the judgment; in restoration they will know him because of the redemption. The same divine Name reveals itself through both modes of action.</p>",
    "43": "<p><strong>ushantechem sham et-darkechem</strong> ('there you will remember your ways'): <em>zakar</em> (H2142, remember) — the memory of covenant failure is a gift, not a burden: it contextualizes the grace of restoration. <strong>veniqottem bifinechem</strong> ('you will loathe yourselves'): <em>qot</em> (H6962, loathe/feel disgust) — the repentance that comes not from fear of punishment but from seeing one's own past against the backdrop of received grace. This is the repentance the restored community will experience after the new exodus.</p>",
    "44": "<p><strong>vide'etem ki ani YHWH baasoti itchem lema'an shemi</strong> ('you will know that I am YHWH when I have dealt with you for my name's sake'): the fourth occurrence of the name-protection motif. The chapter closes with the same divine logic that has governed it throughout: YHWH acts consistently for the sake of his name/character/covenant integrity. <strong>velo kederacheichem haraim</strong> ('and not according to your evil ways'): the restoration is entirely YHWH's initiative, not earned by the people's improved behavior. The new covenant operates from grace, not merit.</p>",
    "45": "<p>New oracle formula: the word of YHWH turns to a brief southern-fire oracle (vv.45-49 in English numbering). This short oracle serves as a transitional appendix to ch 20 and a prelude to the sword oracles of ch 21.</p>",
    "46": "<p><strong>pane darkecha teiman</strong> ('set your face toward the south'): <em>teiman</em> (H8486, south/Negev) — the southern direction toward Jerusalem and Judah from Ezekiel's Babylonian location. <strong>hatteph el-derech negev</strong> ('speak/drip toward the south'): <em>nataph</em> (H5197, drip/drop/prophesy) — used for prophetic utterance that falls like rain-drops (Amos 7:16; Mic 2:6,11). The image of prophecy as dripping/dropping carries the sense of measured, accumulating utterance.</p>",
    "47": "<p><strong>vehitzi baesh</strong> ('I will kindle a fire in you'): the forest-fire oracle — <em>ya'ar hanegev</em> (the forest of the Negev) is an unusual designation, since the Negev is characteristically treeless desert; the forest imagery may be allegorical for Jerusalem's population (cf. ch 21 where the 'forest' becomes the sword oracle against Judah). <strong>kol-panim mineggev tzaphona</strong> ('every face from south to north'): comprehensive — the fire leaves no face unscorched, corresponding to the comprehensive sword-judgment to follow.</p>",
    "48": "<p><strong>verayu kol-basar ki ani YHWH bilati oto</strong> ('all flesh will see that I the LORD have lit this fire; it will not be quenched'): the universal witness formula. The unquenchable fire is the inescapable divine judgment; the prophet's word sets it; YHWH's name ensures it cannot be extinguished by human countermeasures.</p>",
    "49": "<p><strong>va-aMaR ah adonai YHWH hemah omerim li</strong> ('then I said: Ah, Lord GOD! They are saying of me'): Ezekiel's complaint — his hearers dismiss the oracle as merely parabolic (<em>moshel meshalim hu</em>, 'he is a teller of parables'). The prophet is accused of speaking in riddles rather than plain prophecy. This reaction is itself a fulfillment of 33:31-32: hearing words but not acting on them, treating prophecy as entertainment. The chapter that began with YHWH refusing to be consulted ends with the prophet being dismissed as a parable-teller.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'ezekiel')
    merge_comm(existing, EZK_ORIG)
    save_comm('mkt-original', 'ezekiel', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/ezekiel.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/ezekiel.json').read_text())

    all_ok = True
    for ch in [18, 19, 20]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
